import{_ as a,o as e,c as n,ae as s}from"./chunks/framework.BnDe_jy5.js";const b=JSON.parse('{"title":"批量处理","description":"了解如何使用 VideoForge 的批量处理功能，同时处理多个视频任务。","frontmatter":{"title":"批量处理","description":"了解如何使用 VideoForge 的批量处理功能，同时处理多个视频任务。"},"headers":[],"relativePath":"guide/batch-processing.md","filePath":"guide/batch-processing.md"}'),d={name:"guide/batch-processing.md"};function l(r,t,i,o,h,c){return e(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="批量处理指南" tabindex="-1">批量处理指南 <a class="header-anchor" href="#批量处理指南" aria-label="Permalink to &quot;批量处理指南&quot;">​</a></h1><p>VideoForge 的批量处理功能允许你同时对多个视频进行 AI 处理，大大提高工作效率。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>📺 <strong>直播切片</strong> — 将多场直播录屏转化为高光片段</li><li>🎬 <strong>系列视频</strong> — 批量处理课程视频、教程系列</li><li>📱 <strong>多平台分发</strong> — 同一素材批量导出不同格式/分辨率</li><li>🌍 <strong>本地化翻译</strong> — 一键生成多语言版本</li></ul><hr><h2 id="打开批量处理面板" tabindex="-1">打开批量处理面板 <a class="header-anchor" href="#打开批量处理面板" aria-label="Permalink to &quot;打开批量处理面板&quot;">​</a></h2><p>入口：<strong>AI 创作 → 批量处理</strong></p><p>或使用快捷键：<code>Ctrl+Shift+B</code>（Windows）/ <code>⌘⇧B</code>（macOS）</p><hr><h2 id="添加处理任务" tabindex="-1">添加处理任务 <a class="header-anchor" href="#添加处理任务" aria-label="Permalink to &quot;添加处理任务&quot;">​</a></h2><h3 id="方法一-手动添加" tabindex="-1">方法一：手动添加 <a class="header-anchor" href="#方法一-手动添加" aria-label="Permalink to &quot;方法一：手动添加&quot;">​</a></h3><ol><li>点击 <strong>+ 添加任务</strong></li><li>选择视频文件</li><li>选择处理模式</li><li>配置参数</li><li>点击 <strong>确认</strong></li></ol><h3 id="方法二-批量导入" tabindex="-1">方法二：批量导入 <a class="header-anchor" href="#方法二-批量导入" aria-label="Permalink to &quot;方法二：批量导入&quot;">​</a></h3><p>支持一次性导入整个文件夹：</p><ol><li>点击 <strong>批量导入</strong></li><li>选择包含视频文件的文件夹</li><li>设置统一的处理模式和参数</li><li>点击 <strong>开始排队</strong></li></ol><h3 id="方法三-拖拽添加" tabindex="-1">方法三：拖拽添加 <a class="header-anchor" href="#方法三-拖拽添加" aria-label="Permalink to &quot;方法三：拖拽添加&quot;">​</a></h3><p>直接将视频文件或文件夹拖入批量处理面板。</p><hr><h2 id="任务配置" tabindex="-1">任务配置 <a class="header-anchor" href="#任务配置" aria-label="Permalink to &quot;任务配置&quot;">​</a></h2><h3 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><strong>处理模式</strong></td><td>选择 AI 创作模式</td></tr><tr><td><strong>输出目录</strong></td><td>统一设置导出路径</td></tr><tr><td><strong>命名规则</strong></td><td>支持变量：<code>{filename}</code>、<code>{index}</code>、<code>{date}</code></td></tr></tbody></table><h3 id="高级配置" tabindex="-1">高级配置 <a class="header-anchor" href="#高级配置" aria-label="Permalink to &quot;高级配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>并行数</td><td>同时处理的任务数</td><td>1</td></tr><tr><td>失败重试</td><td>失败后自动重试次数</td><td>2</td></tr><tr><td>自动导出</td><td>处理完成后自动导出</td><td>✅</td></tr><tr><td>完成后通知</td><td>全部完成后发送系统通知</td><td>✅</td></tr></tbody></table><hr><h2 id="队列管理" tabindex="-1">队列管理 <a class="header-anchor" href="#队列管理" aria-label="Permalink to &quot;队列管理&quot;">​</a></h2><h3 id="任务状态" tabindex="-1">任务状态 <a class="header-anchor" href="#任务状态" aria-label="Permalink to &quot;任务状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>标识</th><th>说明</th></tr></thead><tbody><tr><td>等待中</td><td>⏳</td><td>排队等待处理</td></tr><tr><td>正在处理</td><td>🔄</td><td>正在 AI 处理</td></tr><tr><td>导出中</td><td>📦</td><td>正在导出文件</td></tr><tr><td>已完成</td><td>✅</td><td>处理成功</td></tr><tr><td>已失败</td><td>❌</td><td>处理失败（可重试）</td></tr><tr><td>已暂停</td><td>⏸️</td><td>用户暂停</td></tr></tbody></table><h3 id="队列操作" tabindex="-1">队列操作 <a class="header-anchor" href="#队列操作" aria-label="Permalink to &quot;队列操作&quot;">​</a></h3><ul><li><strong>暂停全部</strong> — 暂停队列中所有任务</li><li><strong>恢复全部</strong> — 恢复已暂停的任务</li><li><strong>清空已完成</strong> — 移除已完成的任务记录</li><li><strong>清空全部</strong> — 清空整个队列（谨慎操作）</li></ul><h3 id="单任务操作" tabindex="-1">单任务操作 <a class="header-anchor" href="#单任务操作" aria-label="Permalink to &quot;单任务操作&quot;">​</a></h3><ul><li><strong>▶️ 开始</strong> — 立即开始处理此任务</li><li><strong>⏸️ 暂停</strong> — 暂停此任务</li><li><strong>🔄 重试</strong> — 重新处理失败的任务</li><li><strong>🗑️ 移除</strong> — 从队列中移除此任务</li><li><strong>📝 编辑</strong> — 修改任务参数</li></ul><hr><h2 id="进度监控" tabindex="-1">进度监控 <a class="header-anchor" href="#进度监控" aria-label="Permalink to &quot;进度监控&quot;">​</a></h2><h3 id="任务卡片" tabindex="-1">任务卡片 <a class="header-anchor" href="#任务卡片" aria-label="Permalink to &quot;任务卡片&quot;">​</a></h3><p>每个任务卡片显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📹 keynote_presentation.mp4</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>模式：AI 解说       状态：正在处理</span></span>
<span class="line"><span>████████████░░░░░░░░░░  60%</span></span>
<span class="line"><span>预计剩余：3 分钟</span></span></code></pre></div><h3 id="统计面板" tabindex="-1">统计面板 <a class="header-anchor" href="#统计面板" aria-label="Permalink to &quot;统计面板&quot;">​</a></h3><p>底部显示全局统计：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总任务：12    已完成：5    正在处理：2    等待中：4    失败：1</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>总体进度：████████░░░░░░░░░░░░░░░  41%</span></span>
<span class="line"><span>预计剩余：15 分钟</span></span></code></pre></div><hr><h2 id="模板与预设" tabindex="-1">模板与预设 <a class="header-anchor" href="#模板与预设" aria-label="Permalink to &quot;模板与预设&quot;">​</a></h2><h3 id="保存为模板" tabindex="-1">保存为模板 <a class="header-anchor" href="#保存为模板" aria-label="Permalink to &quot;保存为模板&quot;">​</a></h3><p>将常用配置保存为模板：</p><ol><li>配置好处理参数</li><li>点击 <strong>保存为模板</strong></li><li>输入模板名称</li><li>下次使用时直接选择模板</li></ol><h3 id="预设模板" tabindex="-1">预设模板 <a class="header-anchor" href="#预设模板" aria-label="Permalink to &quot;预设模板&quot;">​</a></h3><p>VideoForge 内置以下模板：</p><table tabindex="0"><thead><tr><th>模板名称</th><th>适用场景</th><th>模式</th><th>并行数</th></tr></thead><tbody><tr><td><strong>直播高光切片</strong></td><td>直播录屏</td><td>短视频切片</td><td>2</td></tr><tr><td><strong>课程批量解说</strong></td><td>在线课程</td><td>AI 解说</td><td>1</td></tr><tr><td><strong>系列混剪</strong></td><td>系列素材</td><td>智能混剪</td><td>2</td></tr><tr><td><strong>多语言分发</strong></td><td>出海内容</td><td>视频翻译</td><td>1</td></tr></tbody></table><hr><h2 id="输出管理" tabindex="-1">输出管理 <a class="header-anchor" href="#输出管理" aria-label="Permalink to &quot;输出管理&quot;">​</a></h2><h3 id="自动命名规则" tabindex="-1">自动命名规则 <a class="header-anchor" href="#自动命名规则" aria-label="Permalink to &quot;自动命名规则&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{filename}          → keynote_presentation</span></span>
<span class="line"><span>{index}             → 001, 002, 003</span></span>
<span class="line"><span>{date}              → 2026-03-31</span></span>
<span class="line"><span>{mode}              → ai_commentary</span></span>
<span class="line"><span>{resolution}        → 1080p</span></span></code></pre></div><h3 id="输出目录结构" tabindex="-1">输出目录结构 <a class="header-anchor" href="#输出目录结构" aria-label="Permalink to &quot;输出目录结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输出根目录/</span></span>
<span class="line"><span>├── 001_keynote_presentation/</span></span>
<span class="line"><span>│   ├── final.mp4</span></span>
<span class="line"><span>│   ├── subtitle.srt</span></span>
<span class="line"><span>│   └── thumbnail.jpg</span></span>
<span class="line"><span>├── 002_session2_recording/</span></span>
<span class="line"><span>│   └── ...</span></span></code></pre></div><hr><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><h3 id="任务一直处于-等待中" tabindex="-1">任务一直处于&quot;等待中&quot; <a class="header-anchor" href="#任务一直处于-等待中" aria-label="Permalink to &quot;任务一直处于&quot;等待中&quot;&quot;">​</a></h3><p>检查队列是否被暂停，或并行数是否为 0。</p><h3 id="任务失败率高" tabindex="-1">任务失败率高 <a class="header-anchor" href="#任务失败率高" aria-label="Permalink to &quot;任务失败率高&quot;">​</a></h3><p>常见原因：</p><ol><li>源视频格式不兼容（尝试转为 MP4）</li><li>磁盘空间不足</li><li>API 请求超限（降低并行数）</li><li>网络不稳定</li></ol><h3 id="内存不足" tabindex="-1">内存不足 <a class="header-anchor" href="#内存不足" aria-label="Permalink to &quot;内存不足&quot;">​</a></h3><ul><li>降低并行数（建议设为 1）</li><li>关闭其他占用内存的程序</li><li>使用较低分辨率预览</li></ul><hr><h2 id="快捷操作" tabindex="-1">快捷操作 <a class="header-anchor" href="#快捷操作" aria-label="Permalink to &quot;快捷操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>Windows</th><th>macOS</th></tr></thead><tbody><tr><td>打开批量处理</td><td><code>Ctrl+Shift+B</code></td><td><code>⌘⇧B</code></td></tr><tr><td>添加任务</td><td><code>Ctrl+N</code></td><td><code>⌘N</code></td></tr><tr><td>暂停全部</td><td><code>Ctrl+P</code></td><td><code>⌘P</code></td></tr><tr><td>清空已完成</td><td><code>Ctrl+Shift+C</code></td><td><code>⌘⇧C</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">💡 提示</p><p>对于大型批量任务（如 100+ 视频），建议在夜间无人使用时运行，并设置&quot;完成后通知&quot;以便第二天查看结果。</p></div><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><p>批量处理会消耗大量系统资源。建议在处理期间避免进行其他高负载操作（如游戏、大文件拷贝等）。</p></div>`,67)])])}const u=a(d,[["render",l]]);export{b as __pageData,u as default};
